// determine content type from file extension
// books = epub/pdf, audio = mp3/wav/ogg, video = mp4/mkv, translate = Translate/ subfolder

const items = $input.all();
const results = [];

const videoExts = ['mp4', 'mkv', 'webm', 'mov', 'avi'];
const audioExts = ['mp3', 'm4a', 'ogg', 'wav', 'opus', 'flac', 'aac'];
const bookExts = ['epub'];

for (const item of items) {
  const data = item.json || {};

  // Skip empty results (when folder is empty, NextCloud returns {})
  if (!data.path && !data.type) continue;

  // Skip folders -- we only want files
  if (data.type === 'folder') continue;

  const filePath = data.path || '';
  if (!filePath) continue;

  // Extract filename from path
  const parts = filePath.split('/').filter(Boolean);
  const fileName = parts[parts.length - 1];
  if (!fileName || fileName.startsWith('.') || fileName.startsWith('_')) continue;

  // Decode URL-encoded filenames
  const decodedName = decodeURIComponent(fileName);
  const ext = decodedName.split('.').pop().toLowerCase();

  // Detect which folder the file is in
  const isTranslateFolder = filePath.toLowerCase().includes('/translate/');

  let contentType = null;
  let flags = {};

  if (isTranslateFolder) {
    // Translate folder: only accept book files (epub)
    if (bookExts.includes(ext)) {
      contentType = 'translate-book';
      // Default to French translation (most content is English)
      // Worker will auto-detect source language from EPUB metadata
      flags = { translate: 'fr' };
    }
    // Skip non-book files in Translate folder
    if (!contentType) continue;
  } else {
    // Inbox folder: standard classification
    if (videoExts.includes(ext)) {
      contentType = 'local-video';
    } else if (audioExts.includes(ext)) {
      contentType = 'local-audio';
    } else if (bookExts.includes(ext)) {
      contentType = 'local-book';
    }
  }

  // Skip unsupported file types
  if (!contentType) continue;

  // Generate slug from filename
  const slug = decodedName.toLowerCase()
    .replace(/\.[^.]+$/, '')
    .replace(/[^a-z0-9\s-]/g, '')
    .replace(/\s+/g, '-')
    .substring(0, 60);

  // Build NextCloud path for download/move operations
  const ncFolder = isTranslateFolder ? 'Translate' : 'Inbox';

  results.push({ json: {
    _fileName: decodedName,
    _ncPath: `/Shared/Shared/Pipeline/${ncFolder}/${decodedName}`,
    _contentType: contentType,
    _ext: ext,
    _slug: slug || 'file',
    _source: 'nextcloud',
    _fileSize: parseInt(data.contentLength || '0', 10),
    _flags: flags,
    _ncFolder: ncFolder
  }});
}

// If no processable files found, return empty marker
if (results.length === 0) {
  return [{ json: { _empty: true } }];
}

return results;

// route based on cache check: hit = move to processed, miss = queue

const cacheItems = $input.all();
const classifyData = $('Classify Files').first().json;

// Check content_cache hit
const hasCache = cacheItems.length > 0 && cacheItems[0].json.content_key;

// Also check if this file is already queued (pending/processing) in pipeline_queue
// This prevents re-queuing during the processing window (which can be 60+ min for books)
let alreadyQueued = false;
if (!hasCache) {
  // We need the content key -- but it's computed after download, which hasn't happened yet.
  // Instead, check by filename: look for pending/processing jobs from nextcloud
  // with this filename in their message_text metadata.
  const fileName = classifyData._fileName || '';
  if (fileName) {
    try {
      // This node receives PostgreSQL output from Cache Check.
      // We can't run another query here, but we can use the _fileName
      // to mark it for a downstream queue check.
      // Actually, we'll use a simpler approach: check if the file was
      // already seen by looking at a broader cache check in the query.
    } catch(e) {}
  }
}

return [{ json: {
  ...classifyData,
  _hasCache: !!hasCache,
  _cachedKey: hasCache ? cacheItems[0].json.content_key : null
} }];

// save downloaded file to /tmp/ and compute content key from SHA256

const fs = require('fs');
const { execFileSync } = require('child_process');

const classifyData = $('Check Cache Result').first().json;
const fileName = classifyData._fileName;
const stamp = String(Date.now()) + '_' + Math.random().toString(36).slice(2, 6);
// Use persistent directory for files that need to survive across executions
const pipeDir = '/home/node/.n8n/pipeline-files';
try { const fs2 = require('fs'); if (!fs2.existsSync(pipeDir)) fs2.mkdirSync(pipeDir, {recursive: true}); } catch(e) {}
const localPath = `${pipeDir}/nc_${stamp}_${fileName}`;

// Get binary data reference from Download File node
const binaryData = $input.first().binary;
if (!binaryData || !binaryData.data) {
  throw new Error('No binary data from NextCloud download');
}

const binaryInfo = binaryData.data;

// filesystem-v2: binary stored on disk, id contains the path
// id format: "filesystem-v2:workflows/<wfId>/executions/<exId>/binary_data/<uuid>"
if (binaryInfo.id && binaryInfo.id.startsWith('filesystem-v2:')) {
  const storagePath = '/home/node/.n8n/storage/' + binaryInfo.id.replace('filesystem-v2:', '');
  if (!fs.existsSync(storagePath)) {
    throw new Error('Binary storage file not found: ' + storagePath);
  }
  fs.copyFileSync(storagePath, localPath);
} else if (binaryInfo.data && binaryInfo.data.length > 100) {
  // Legacy base64 mode (fallback)
  const buffer = Buffer.from(binaryInfo.data, 'base64');
  fs.writeFileSync(localPath, buffer);
} else {
  throw new Error('Cannot read binary data. id=' + (binaryInfo.id || 'none') + ', data_len=' + (binaryInfo.data || '').length);
}

const fileSize = fs.statSync(localPath).size;
if (fileSize < 1000) throw new Error('Downloaded file too small: ' + fileSize + ' bytes');

// Compute content key hash using sha256sum CLI
let hashPrefix;
try {
  const hashOut = execFileSync('sha256sum', [localPath], { encoding: 'utf-8', timeout: 60000 });
  hashPrefix = hashOut.split(' ')[0].substring(0, 8);
} catch(e) {
  hashPrefix = String(fileSize).substring(0, 8).padStart(8, '0');
}

const slug = classifyData._slug || 'file';
const contentKey = `file:${hashPrefix}_${slug}`;

return [{ json: {
  ...classifyData,
  _filePath: localPath,
  _fileSize: fileSize,
  _contentKey: contentKey,
  _tmpStamp: stamp
} }];

