// check for existing pending/processing job to prevent duplicates

const queueResult = $input.all();
const classifyData = $('Check Cache Result').first().json;

const hasPending = queueResult.length > 0 && queueResult[0].json.id;

if (hasPending) {
  // File already queued -- skip entirely (don't download, don't re-queue)
  return [];
}

// No pending job -- continue to download
return [{ json: classifyData }];
